parameters.jsCode:
const job = $('GetPendingJob').first().json;
return [{
  json: {
    id: job.id,
    name: job.title,
    type: 'task',
    status: 'in_progress',
    agent: job.agent,
    prompts: {
      user: job.instructions,
      core: 'core-prompt-v1',
      context: job.instructions
    },
    metadata: {
      inputType: 'task',
      telegram: {
        channelId: job.channel_id,
        messageId: null
      }
    }
  }
}];

let input = $input.first().json;

// Detect task JSON format vs legacy format
const isTaskJson = input.prompts !== undefined;

const inputType = isTaskJson ? (input.metadata?.inputType ?? 'unknown')       : (input.InputType ?? 'unknown');
const userInput = isTaskJson ? (input.prompts?.user ?? '')                    : (input.RequestInput?.input ?? '');
const channelID = isTaskJson ? (input.metadata?.telegram?.channelId ?? null) : (input.ChannelInformation?.ChannelID ?? null);
const messageID = isTaskJson ? (input.metadata?.telegram?.messageId ?? null) : (input.ChannelInformation?.MessageID ?? null);

return {
  InputType: inputType,
  RequestInput: {
    input: userInput + "\n\n###OUTPUT###\nStart your final answer with the exact token RESPONSE: on its own line."
  },
  ChannelInformation: {
    ChannelID: channelID,
    MessageID: messageID
  }
};

parameters.query:
SELECT channel_id, soul, user_profile, preferences, current_focus, onboarding_step
FROM user_profile
WHERE channel_id = {{ $('SetVars').first().json.ChannelInformation.ChannelID }}
LIMIT 1;

parameters.jsCode:
try {
  const fs = require('fs');
  const allItems = $input.all();
  const profile = (allItems.length > 0 && allItems[0].json && allItems[0].json.channel_id != null)
    ? allItems[0].json
    : null;

  const vars = $('SetVars').first().json;
  const channelID = vars.ChannelInformation.ChannelID;

  const hasProfile = profile !== null;
  const onboardingStep = hasProfile ? (profile.onboarding_step ?? 1) : 1;

  const now = new Date();
  const timeContext = `DATE & TIME:
Current datetime: ${now.toISOString()}
Local datetime:   ${now.toLocaleString('en-GB', { timeZone: 'Europe/Amsterdam', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
Timezone:         Europe/Amsterdam
Day of week:      ${now.toLocaleDateString('en-GB', { timeZone: 'Europe/Amsterdam', weekday: 'long' })}`;

  const vault_navigation = $('Vault Navigation').first().json.stdout;
  let systemPrompt = '';

  if (!hasProfile || onboardingStep > 0) {
    const step = onboardingStep || 1;
    const steps = {
      1: `You are setting yourself up as the user's personal AI assistant.\n\nYour ONLY task right now is to warmly greet the user and ask this one question:\n"Before we dive in, I'd love to define my own identity. What should I call myself, and how would you describe my personality and purpose? For example: 'Baxter - sharp and direct - helps me stay on top of work and life.'"\n\nWhen they respond, call the UpdateProfile tool with:\n- soul: their answer, preserved exactly\n- next_onboarding_step: 2\nLeave all other fields as empty strings.\n\nOUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,
      2: `You are Baxter, a personal AI assistant currently in setup.\n\nYour soul has been defined. Now ask:\n"Great. Now tell me a bit about you - your work, interests, goals, whatever you'd like me to keep in mind long-term."\n\nWhen they respond, call UpdateProfile with:\n- user_profile: a structured summary of what they shared (name, role, interests, goals)\n- next_onboarding_step: 3\nLeave other fields as empty strings.\n\nOUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,
      3: `You are Baxter, a personal AI assistant currently in setup.\n\nOne last question:\n"Almost done - how do you prefer I communicate? Concise and direct, or more detailed? Any language or format preferences?"\n\nWhen they respond, call UpdateProfile with:\n- preferences: their answer\n- next_onboarding_step: 0\nLeave other fields as empty strings. After saving, confirm setup is complete and you are ready to help.\n\nOUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,
    };
    systemPrompt = timeContext + '\n\n' + (steps[step] || steps[1]);
  } else {
    const soul        = profile.soul          || 'Baxter - curious, helpful and critical - personal AI assistant';
    const userProfile = profile.user_profile  || '';
    const prefs       = profile.preferences   || 'Clear and direct';
    const focus       = profile.current_focus || '';

    const template = fs.readFileSync('/data/prompts/baxter-job.md', 'utf8')
      .split('\n').filter(l => !l.startsWith('#')).join('\n').trim();

    const aboutUser    = userProfile ? `ABOUT THE USER:\n${userProfile}\n\n` : '';
    const commStyle    = prefs       ? `COMMUNICATION STYLE: ${prefs}\n\n`   : '';
    const currentFocus = focus       ? `CURRENT FOCUS: ${focus}\n\n`         : '';

    // Task context (populated for background subtasks)
    let taskContext = '';
    try {
      const taskCtx = $('FetchTaskContext').first().json;
      if (taskCtx && taskCtx.parent_goal) {
        taskContext += `TASK GOAL: This subtask is part of the larger goal "${taskCtx.parent_name}":\n${taskCtx.parent_goal}\n\n`;
      }
      if (taskCtx && taskCtx.completed_siblings && taskCtx.completed_siblings.length > 0) {
        const sibLines = taskCtx.completed_siblings
          .map(s => `- ${s.name}:\n  ${(s.result || '(no result)').substring(0, 800)}`)
          .join('\n');
        taskContext += `COMPLETED PRIOR SUBTASKS (build on these results - do not repeat them):\n${sibLines}\n\n`;
      }
    } catch(e) { /* no task context - standalone task */ }

    systemPrompt = timeContext + '\n\n' + template
      .replace('{{SOUL}}', soul)
      .replace('{{ABOUT_USER}}', aboutUser)
      .replace('{{COMM_STYLE}}', commStyle)
      .replace('{{CURRENT_FOCUS}}', currentFocus)
      .replace('{{TASK_CONTEXT}}', taskContext)
      .replace('{{VAULT_NAVIGATION}}', vault_navigation);
  }

  return [{ json: { systemPrompt, onboardingStep, hasProfile } }];

} catch (error) {
  const vars = $('SetVars').first().json;
  const channelID = vars.ChannelInformation.ChannelID;
  const now = new Date();
  const vault_navigation = $('Vault Navigation').first().json.stdout || '';
  const systemPrompt = `DATE & TIME: ${now.toISOString()} (Europe/Amsterdam)\n\nYou are Baxter, a personal AI assistant.\n\nLANGUAGE: Always respond in English only.\nFORMAT: Use markdown where it aids readability; plain prose for conversational replies.\n\nTOOLS: You MUST actually invoke a tool to use it - never describe a tool call without invoking it first. All tool calls happen before you write RESPONSE:.\n1. LongTermMemory for past context.\n2. ExecQuery for recent history (WHERE channel_id = ${channelID} LIMIT 10).\n3. SearchVault / ReadVaultNote for vault notes.\n4. WriteVaultNote to save to Atlas/Baxter/.\n5. ProjectManager for tasks.\n6. CalendarManager for events.\n7. NewsTool for news.\n8. ResearchAgent for deep research.\n\nTASK DELEGATION: Use CreateTask for background work - invoke the tool, do not just describe it.\n\nOUTPUT: Your final answer must start with the exact word RESPONSE: on its own line.`;
  return [{ json: { systemPrompt, onboardingStep: 0, hasProfile: false, fallback: true } }];
}

